export function TechStack() {
  const sectionRef = useRef<HTMLElement>(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, []);

  return (
    <section
      ref={sectionRef}
      id="stack"
      className="relative py-32 px-6 overflow-hidden"
    >
      <div className="max-w-6xl mx-auto">
        {/* Section header */}
        <div
          className={`text-center mb-16 transition-all duration-1000 ${
            isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"
          }`}
        >
          <div className="inline-flex items-center gap-2 px-3 py-1 rounded-full border border-border bg-card/50 text-xs text-muted-foreground mb-4">
            <Layers className="w-3 h-3" />
            Technology Stack
          </div>
          <h2 className="text-4xl md:text-5xl font-bold tracking-tight">
            Engineered with{" "}
            <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-orange-400">
              Precision
            </span>
          </h2>
          <p className="mt-4 text-muted max-w-2xl mx-auto">
            A carefully selected stack of battle-tested technologies for
            maximum performance and reliability.
          </p>
        </div>

        {/* Tech grid */}
        <div
          className={`grid grid-cols-3 md:grid-cols-5 lg:grid-cols-9 gap-6 transition-all duration-1000 delay-200 ${
            isVisible ? "opacity-100 translate-y-0" : "opacity-0 translate-y-8"
          }`}
        >
          {techStack.map((tech, index) => (
            <div
              key={tech.name}
              className="group flex flex-col items-center gap-3"
              style={{ animationDelay: `${index * 50}ms` }}
            >
              <div
                className="relative p-4 rounded-xl border border-border bg-card/30 transition-all duration-300 group-hover:border-primary/50 group-hover:bg-card/50 group-hover:-translate-y-1"
                style={
                  {
                    "--tech-color": tech.color,
                  } as React.CSSProperties
                }
              >
                {/* Glow effect on hover */}
                <div
                  className="absolute inset-0 rounded-xl opacity-0 group-hover:opacity-100 transition-opacity duration-300 blur-xl"
                  style={{ backgroundColor: `${tech.color}20` }}
                />
                <div className="relative text-muted transition-all duration-300 group-hover:text-foreground">
                  <div
                    className="transition-all duration-300 opacity-40 group-hover:opacity-100"
                    style={
                      {
                        "--tw-text-opacity": 1,
                        color: "currentColor",
                      } as React.CSSProperties
                    }
                  >
                    <div className="group-hover:drop-shadow-lg transition-all duration-300">
                      {tech.icon}
                    </div>
                  </div>
                </div>
              </div>
              <span className="text-xs text-muted-foreground group-hover:text-foreground transition-colors duration-300 font-medium">
                {tech.name}
              </span>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
